def handle_user_by_id(request, user_id):
    """Single user endpoint."""
    # Simulated user store
    users = {
        '1': {'id': '1', 'username': 'alice', 'email': 'alice@example.com', 'role': 'admin'},
        '2': {'id': '2', 'username': 'bob', 'email': 'bob@example.com', 'role': 'user'},
        '3': {'id': '3', 'username': 'charlie', 'email': 'charlie@example.com', 'role': 'user'},
    }

    if request.method == 'GET':
        user = users.get(user_id)
        if not user:
            response = jsonify({'error': 'Not Found', 'message': f'User {user_id} not found'})
            response.status_code = 404
            return response

        response = jsonify({'user': user})
        response.status_code = 200
        return response

    elif request.method == 'PUT':
        user = users.get(user_id)
        if not user:
            response = jsonify({'error': 'Not Found', 'message': f'User {user_id} not found'})
            response.status_code = 404
            return response

        update_data = request.get_json(silent=True) or {}
        updated_user = {**user, **update_data, 'id': user_id}
        response = jsonify({
            'message': 'User updated successfully',
            'user': updated_user
        })
        response.status_code = 200
        return response

    elif request.method == 'PATCH':
        user = users.get(user_id)
        if not user:
            response = jsonify({'error': 'Not Found', 'message': f'User {user_id} not found'})
            response.status_code = 404
            return response

        patch_data = request.get_json(silent=True) or {}
        patched_user = {**user, **patch_data, 'id': user_id}
        response = jsonify({
            'message': 'User partially updated successfully',
            'user': patched_user
        })
        response.status_code = 200
        return response

    elif request.method == 'DELETE':
        user = users.get(user_id)
        if not user:
            response = jsonify({'error': 'Not Found', 'message': f'User {user_id} not found'})
            response.status_code = 404
            return response

        response = jsonify({
            'message': f'User {user_id} deleted successfully'
        })
        response.status_code = 200
        return response

    else:
        response = jsonify({'error': f'Method {request.method} not allowed'})
        response.status_code = 405
        return response


